"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { cva, type VariantProps } from "class-variance-authority";
import { Spinner } from "@/components/ui/spinner";
import type * as React from "react";
import { cn } from "@/lib/utils";
import { disabled, colorTransition, focusRing, iconMuted, iconMutedSolid } from "@/lib/recipes";
import { X } from "lucide-react";

// Button variant vocabulary follows DESIGN.md: primary / secondary /
// tertiary / destructive. Primary is monochrome by default -- it reads
// the --primary / --on-primary / --primary-hover / --primary-active
// chain so a consumer that redefines --primary in a downstream layer
// gets their brand color for free without any callsite edits.
//
// `warning` is a semantic status role we keep as an extra variant for
// caution-flavored actions; it isn't in DESIGN.md's core vocabulary but
// pairs consistently with warning badges and progress.
export const buttonVariants = cva(
  [
    "relative inline-flex shrink-0 items-center justify-center whitespace-nowrap",
    "cursor-pointer",
    "[&_svg]:pointer-events-none [&_svg]:shrink-0",
    // Extend the tap target to 44px on coarse pointers without changing
    // visual size.
    "pointer-coarse:after:absolute pointer-coarse:after:size-full pointer-coarse:after:min-h-11 pointer-coarse:after:min-w-11",
    // No outside focus ring on Button: keyboard focus mirrors the
    // hover state per variant. See each variant's focus-visible: rule
    // below.
    "outline-none",
    colorTransition,
    disabled,
  ].join(" "),
  {
    defaultVariants: { size: "md", variant: "primary", shape: "square", shadow: false },
    variants: {
      // Heights per DESIGN.md: sm=24, md=32, lg=40. Padding follows
      // the compact / default / roomy ramp (10 / 14 / 16 px horizontal).
      size: {
        sm: "h-6 px-2.5 gap-1.5 text-button-12",
        md: "h-8 px-3.5 gap-2 text-button-14",
        lg: "h-10 px-4 gap-2 text-button-16",
      },
      // Each variant pairs hover: and focus-visible: with the same
      // classes so a keyboard-focused button reads exactly like a
      // pointer-hovered one. No ring; the fill/border shift is the
      // whole affordance.
      variant: {
        // Primary reads the --primary var chain so brand overrides
        // flow through automatically. Icon uses opacity-based mute so
        // the on-primary color stays intact but the glyph still lifts
        // on interaction, matching iconMuted's rest-vs-active pattern.
        primary:
          "bg-primary text-on-primary hover:bg-primary-hover focus-visible:bg-primary-hover active:bg-primary-active " +
          iconMutedSolid,
        // Secondary is the elevated bordered button: same surface as
        // cards and popups (--surface-elevated -> pure white in light,
        // palette rung in dark), with a hairline border. Hover tints
        // subtly via --surface-elevated-hover; border stays stable so
        // the whole button doesn't shimmer on hover.
        secondary:
          "bg-surface-elevated text-ink border border-hairline hover:bg-surface-elevated-hover focus-visible:bg-surface-elevated-hover active:bg-surface-1 " +
          iconMuted,
        // Tertiary is the transparent ghost: reads as a link-styled
        // control until interaction, then picks up a gray tint.
        tertiary:
          "bg-transparent text-ink hover:bg-surface-1 focus-visible:bg-surface-1 active:bg-surface-2 " +
          iconMuted,
        // Warning: caution-flavored action, uses the fixed warning role.
        warning:
          "bg-warning text-warning-fg hover:bg-warning-hover focus-visible:bg-warning-hover active:bg-warning-active " +
          iconMutedSolid,
        // Destructive: irreversible action, uses the fixed error role.
        destructive:
          "bg-error text-error-fg hover:bg-error-hover focus-visible:bg-error-hover active:bg-error-active " +
          iconMutedSolid,
      },
      // Three shapes only. `square` (6px) is the default control shape;
      // `pill` (full radius) covers both dismissible chips and marketing
      // CTAs; `circle` (full radius) is `pill` with an equal width/height
      // for icon-only buttons.
      shape: {
        square: "rounded-[var(--radius-6)]",
        pill: "rounded-full",
        circle: "rounded-full",
      },
      shadow: {
        true: "shadow-card",
        false: "",
      },
    },
  },
);

export interface ButtonProps extends useRender.ComponentProps<"button"> {
  variant?: VariantProps<typeof buttonVariants>["variant"];
  size?: VariantProps<typeof buttonVariants>["size"];
  /** Corner shape. `square` (6px) is default; `pill` (full) for chips and marketing CTAs; `circle` (full, equal width/height) for icon-only. */
  shape?: VariantProps<typeof buttonVariants>["shape"];
  /** Adds a subtle elevation shadow. Typically paired with `shape="pill"` on marketing pages. */
  shadow?: boolean;
  icon?: React.ReactNode;
  iconPosition?: "left" | "right";
  loading?: boolean;
  disabled?: boolean;
  /**
   * When provided, renders a trailing × sub-button that calls this handler
   * without triggering the parent Button's onClick. Use for dismissible
   * chips (applied filters, selected labels, chosen recipients), typically
   * with `shape="pill"`.
   */
  onRemove?: () => void;
  /** Accessible label for the × sub-button. */
  removeLabel?: string;
}

const iconOnlyWidth: Record<NonNullable<ButtonProps["size"]>, string> = {
  sm: "w-6 px-0",
  md: "w-8 px-0",
  lg: "w-10 px-0",
};

export function Button({
  className,
  variant,
  size,
  shape,
  shadow,
  icon,
  iconPosition = "left",
  loading,
  disabled: isDisabled,
  onRemove,
  removeLabel = "Remove",
  render,
  children,
  ...props
}: ButtonProps): React.ReactElement {
  const effectiveSize: NonNullable<ButtonProps["size"]> = size ?? "md";
  const isIconOnly = icon != null && !children;
  const iconOnly = isIconOnly ? iconOnlyWidth[effectiveSize] : "";

  if (process.env.NODE_ENV !== "production" && isIconOnly && !props["aria-label"]) {
    console.warn(
      "[Button] Icon-only buttons must have an `aria-label` describing the action.",
    );
  }

  const content = loading ? (
    <Spinner size="sm" />
  ) : (
    <>
      {icon && iconPosition === "left" && icon}
      {children}
      {icon && iconPosition === "right" && icon}
      {onRemove && (
        <span
          role="button"
          tabIndex={0}
          aria-label={removeLabel}
          // Stop mousedown/pointerdown so a parent trigger built on
          // floating-ui's useClick (which fires on mousedown by default)
          // doesn't open its popup when the user clicks the X. onClick
          // alone runs too late.
          onMouseDown={(e) => e.stopPropagation()}
          onPointerDown={(e) => e.stopPropagation()}
          onClick={(e) => {
            e.stopPropagation();
            onRemove();
          }}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault();
              e.stopPropagation();
              onRemove();
            }
          }}
          className={cn(
            "-me-1 inline-flex size-4 shrink-0 items-center justify-center rounded-full opacity-70",
            "hover:bg-surface-2 hover:opacity-100",
            focusRing,
            colorTransition,
          )}
          data-slot="button-remove"
        >
          <X className="size-2.5" strokeWidth={2.5} />
        </span>
      )}
    </>
  );

  const typeValue: React.ButtonHTMLAttributes<HTMLButtonElement>["type"] =
    render ? undefined : "button";

  const defaultProps = {
    className: cn(buttonVariants({ size: effectiveSize, variant, shape, shadow }), iconOnly, className),
    "data-slot": "button",
    type: typeValue,
    disabled: isDisabled || loading,
    children: content,
  };

  return useRender({
    defaultTagName: "button",
    props: mergeProps<"button">(defaultProps, props),
    render,
  });
}
